questionvariables.text:
/* Randomized speeds and times */
v_ship: 15 + rand(10);     /* Speed of ship in km/h */
v_current: 3 + rand(5);    /* Speed of water current in km/h */
time_h: 2 + rand(3);       /* Time spent traveling in hours */

/* Calculations for the Resultant Vector */
/* Assuming ship goes East (x-axis) and current goes North (y-axis) */
dist_east: v_ship * time_h;
dist_north: v_current * time_h;

/* Resultant Displacement (Magnitude) */
disp_mag: sqrt(dist_east^2 + dist_north^2);
ta_displacement: float(round(disp_mag * 10) / 10);

/* Resultant Velocity (Magnitude) */
vel_mag: sqrt(v_ship^2 + v_current^2);
ta_velocity: float(round(vel_mag * 10) / 10);

/* Angle (Direction) from East */
direction_deg: (180/float(%pi)) * atan(v_current/v_ship);
ta_direction: float(round(direction_deg * 10) / 10);
